fn process_refresh_obligation(program_id: &Pubkey, accounts: &[AccountInfo]) -> ProgramResult {
    let mut obligation = Obligation::unpack(&obligation_info.data.borrow())?;

    let mut deposited_value: u128 = 0;
    let mut borrowed_value: u128 = 0;

    for (index, collateral) in obligation.deposits.iter_mut().enumerate() {
        let deposit_reserve = Reserve::unpack(&deposit_reserve_info.data.borrow())?;

        let decimals = 10u64.pow(deposit_reserve.liquidity.mint_decimals as u32);

        let market_value = (collateral.deposited_amount as u128)
            * (deposit_reserve.liquidity.market_price as u128)
            / (decimals as u128);

        deposited_value += market_value;
    }

    obligation.deposited_value = deposited_value;
    obligation.borrowed_value = borrowed_value;
    Obligation::pack(obligation, &mut obligation_info.data.borrow_mut())?;
    Ok(())
}
